#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;
use Date::Manip;

# Function to extract text from PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    my $text = '';
    for my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->page($page);
        $text .= $page_obj->text();
    }

    return $text;
}

# Function to find specific patterns in the extracted text
sub find_info {
    my ($text) = @_;

    my $author = $text =~ /Author:\s*(.*)/i ? $1 : 'Unknown';
    my $date = $text =~ /Date:\s*(.*)/i ? $1 : 'Unknown';
    my $table = $text =~ /Table\s*(\d+)/i ? $1 : 'Not found';

    return ($author, $date, $table);
}

# Main function
sub main {
    my $pdf_file = shift;

    # Extract the text from the PDF
    my $text = extract_text($pdf_file);

    # Decode any non-ASCII characters
    $text = decode('utf8', $text);

    # Find the author, date, and table information
    my ($author, $date, $table) = find_info($text);

    # Output the findings
    print "Author: $author\n";
    print "Date: $date\n";
    print "Table: $table\n";
